import azure.durable_functions as df
import azure.functions as func

myApp = df.DFApp(http_auth_level=func.AuthLevel.ANONYMOUS)

# Orchestrator function — must be deterministic; no I/O inside
@myApp.orchestration_trigger(context_name="context")
def orchestrator(context: df.DurableOrchestrationContext):
    work_items = ["item-1", "item-2", "item-3"]
    # Launch all activity functions in parallel
    tasks = [context.call_activity("process_item", item) for item in work_items]
    results = yield context.task_all(tasks)   # fan-in: wait for all
    return {"results": results}

# Activity function — can do I/O
@myApp.activity_trigger(input_name="item")
def process_item(item: str) -> str:
    return f"{item}-done"

# HTTP trigger that starts the orchestration
@myApp.route(route="start")
@myApp.durable_client_input(client_name="client")
async def http_start(req: func.HttpRequest, client: df.DurableOrchestrationClient):
    instance_id = await client.start_new("orchestrator", None, None)
    return client.create_check_status_response(req, instance_id)
